<?php
// Comprehensive Force Deployment Script v3
$files = [
    'index.html' => '',
    'theme.css' => '',
    'review.html' => ''
];

foreach ($files as $name => $base64) {
    file_put_contents($name, base64_decode($base64));
    echo "Restored $name successfully.<br>";
}
echo "Full restoration complete.";
